8	interface VariableRowProps {
9	  marketId: string;
10	  /** The market being viewed — edits go through this market's endpoint */
11	  targetMarket: Market;
12	}
13	
14	export function VariableRow({ marketId, targetMarket }: VariableRowProps) {
15	  const { data } = useMarket(marketId);
16	  const { session, isConfigured } = useSession();
17	  const { addAssumption, removeAssumption, hasAssumption, getAssumption, contextPayload } = useAssumptions();
18	  const mutation = useProbabilityEdit(targetMarket.id);
19	
20	  const [editingOutcomeId, setEditingOutcomeId] = useState<string | null>(null);
21	  const [editValue, setEditValue] = useState(0.5);
22	
23	  if (!data) return null;
24	
25	  const m = data.market;
26	  const isAssumed = hasAssumption(m.id);
27	  const assumption = getAssumption(m.id);
28	  const isTargetMarket = m.id === targetMarket.id;
29	
30	  const handleAssume = (outcomeId: string) => {
31	    if (isAssumed && assumption?.outcomeId === outcomeId) {
32	      removeAssumption(m.id);
33	    } else {
34	      addAssumption({
35	        variableId: m.variableId,
36	        outcomeId,
37	        label: m.title,
38	      });
39	    }
40	  };
41	
42	  const handleStartEdit = (outcomeId: string, currentP: number) => {
43	    setEditingOutcomeId(outcomeId);
44	    setEditValue(currentP);
45	  };
46	
47	  const handleSubmitEdit = () => {
48	    if (!editingOutcomeId || !isConfigured) return;
49	    mutation.mutate({
50	      payload: {
51	        accountId: session.accountId,
52	        variableId: isTargetMarket ? targetMarket.variableId : m.variableId,
53	        target: { kind: "marginal", outcomeId: editingOutcomeId, probability: editValue },
54	        context: contextPayload,
55	        idempotencyKey: crypto.randomUUID(),
56	      },
57	      session,
58	    });
59	    setEditingOutcomeId(null);
60	  };
61	
62	  return (
63	    <div style={{
64	      ...rowStyle,
65	      ...(isAssumed ? assumedRowStyle : {}),
66	      ...(isTargetMarket ? targetRowStyle : {}),
67	    }}>
68	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
69	        <span style={{ fontSize: "0.85rem", fontWeight: isTargetMarket ? 700 : 500 }}>
70	          {m.title}
71	          {isTargetMarket && <span style={{ fontSize: "0.7rem", color: "var(--color-primary)", marginLeft: 6 }}>(current)</span>}
72	        </span>
73	        {isAssumed && (
74	          <span style={assumedBadge}>
75	            ASSUMED: {assumption?.outcomeId}
76	          </span>
77	        )}
78	      </div>
79	
80	      <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
81	        {m.outcomes.map((o) => {
82	          const p = m.marginals[o.id] ?? 0;
83	          const isEditing = editingOutcomeId === o.id;
84	          const isThisAssumed = isAssumed && assumption?.outcomeId === o.id;
85	
86	          return (
87	            <div key={o.id} style={{ flex: 1, minWidth: 100 }}>
88	              {/* Probability display + inline bar */}
89	              <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
90	                <div style={{ flex: 1 }}>
91	                  <div style={{ height: 20, borderRadius: 4, background: "var(--color-border)", overflow: "hidden", position: "relative" }}>
92	                    <div style={{
93	                      height: "100%",
94	                      width: `${(isEditing ? editValue : p) * 100}%`,
95	                      borderRadius: 4,
96	                      background: isThisAssumed ? "var(--color-primary)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)",
97	                      opacity: isAssumed && !isThisAssumed ? 0.3 : 0.7,
98	                      transition: "width 0.2s ease",
99	                    }} />
100	                    <span style={{
101	                      position: "absolute",
102	                      top: 2,
103	                      left: 6,
104	                      fontSize: "0.7rem",
105	                      fontWeight: 600,
106	                      color: "var(--color-text)",
107	                    }}>
108	                      {o.name}: {formatProbability(isEditing ? editValue : p)}
