export interface MarketOutcome {
  id: string;
  name: string;
}

export type MarketStatus = "active" | "resolved" | "closed" | "draft";
export type MarketListStatusFilter = MarketStatus | "all";
export type MarketListSort = "volume" | "liquidity" | "created";

export interface MarketListFilters {
  status?: MarketListStatusFilter;
  sort?: MarketListSort;
  q?: string;
}

export interface MarketSummary {
  id: string;
  title: string;
  status: MarketStatus;
  liquidity: number;
  volume: number;
  expires_at: string;
}

export interface Market {
  id: string;
  title: string;
  description: string;
  variableId: string;
  status: MarketStatus;
  resolution?: string;
  resolutionProbabilities?: Record<string, number>;
  outcomes: MarketOutcome[];
  marginals: Record<string, number>;
  liquidity: number;
  volume: number;
  created_at: string;
  expires_at: string;
}

export interface MarketListResponse {
  markets: MarketSummary[];
  count: number;
  meta: Meta;
}

export interface MarketDetailResponse {
  market: Market;
  meta: Meta;
}

